insert into public.exercises (id, name, muscle_group, equipment, target, secondary_muscles, instructions, gif_path) values
  ('db-1316', 'barbell bent arm pullover', 'Back', 'Barbell', 'lats', ARRAY['triceps','chest']::text[], ARRAY['Lie flat on a bench with your head at one end and your feet on the floor.','Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.','Lower the barbell behind your head while keeping your arms slightly bent.','Pause for a moment, then raise the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'cA9FuWG'),
  ('db-0027', 'barbell bent over row', 'Back', 'Barbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Bend forward at the hips while keeping your back straight and chest up.','Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Pull the barbell towards your lower chest by retracting your shoulder blades and squeezing your back muscles.','Pause for a moment at the top, then slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'eZyBC3j'),
  ('db-2407', 'barbell biceps curl (with arm blaster)', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.','Place your upper arms against the arm blaster, keeping your elbows close to your torso.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'aee2Fcj'),
  ('db-0028', 'barbell clean and press', 'Legs', 'Barbell', 'quads', ARRAY['hamstrings','glutes','shoulders','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart and the barbell on the floor in front of you.','Bend your knees and hinge at the hips to lower down and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Drive through your heels and extend your hips and knees to lift the barbell off the floor, keeping it close to your body.','As the barbell reaches your thighs, explosively extend your hips, shrug your shoulders, and pull the barbell up towards your chest.','As the barbell reaches chest height, quickly drop under it and catch it at shoulder level, with your elbows pointing forward and your palms facing up.','From the catch position, press the barbell overhead by extending your arms and pushing the barbell straight up.','Lower the barbell back down to the starting position and repeat for the desired number of repetitions.']::text[], 'SGY8Zui'),
  ('db-0029', 'barbell clean-grip front squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, with your elbows pointing forward.','Lower your body by bending your knees and pushing your hips back, as if you are sitting back into a chair.','Keep your chest up and your back straight as you lower down, making sure your knees do not go past your toes.','Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to stand back up, extending your hips and knees.','Repeat for the desired number of repetitions.']::text[], 'qi996YS'),
  ('db-0030', 'barbell close-grip bench press', 'Arms', 'Barbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.','Pause for a moment when the barbell touches your chest.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'J6Dx1Mu'),
  ('db-0031', 'barbell curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing forward.','Keep your elbows close to your torso and exhale as you curl the weights while contracting your biceps.','Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale as you slowly begin to lower the bar back to the starting position.','Repeat for the desired number of repetitions.']::text[], '25GPyDY'),
  ('db-0032', 'barbell deadlift', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and the barbell on the ground in front of you.','Bend your knees and hinge at the hips to lower your torso and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Keep your back straight and chest lifted as you drive through your heels to lift the barbell off the ground, extending your hips and knees.','As you stand up straight, squeeze your glutes and keep your core engaged.','Lower the barbell back down to the ground by bending at the hips and knees, keeping your back straight.','Repeat for the desired number of repetitions.']::text[], 'ila4NZS'),
  ('db-0033', 'barbell decline bench press', 'Chest', 'Barbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie on a decline bench with your feet secured and your head lower than your hips.','Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.','Pause for a moment at the bottom, then push the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'GrO65fd'),
  ('db-0034', 'barbell decline bent arm pullover', 'Back', 'Barbell', 'lats', ARRAY['triceps','chest']::text[], ARRAY['Lie down on a decline bench with your head lower than your hips and your feet secured.','Hold a barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.','Lower the barbell behind your head in a controlled manner, keeping your arms slightly bent.','Pause for a moment, then raise the barbell back to the starting position by contracting your lats.','Repeat for the desired number of repetitions.']::text[], 'hMEptv0'),
  ('db-0035', 'barbell decline close grip to skull press', 'Arms', 'Barbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie on a decline bench with your head lower than your feet and hold a barbell with a close grip.','Lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.','Pause for a moment, then extend your arms to press the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'LMGXZn8'),
  ('db-1255', 'barbell decline pullover', 'Chest', 'Barbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie down on a decline bench with your head lower than your hips and your feet secured.','Hold the barbell with a pronated grip (palms facing away from you) and your hands slightly wider than shoulder-width apart.','Extend your arms above your chest, keeping a slight bend in your elbows.','Lower the barbell in an arc motion behind your head, feeling a stretch in your chest and shoulders.','Pause for a moment, then return the barbell to the starting position by reversing the motion.','Repeat for the desired number of repetitions.']::text[], '9sgNE2O'),
  ('db-0036', 'barbell decline wide-grip press', 'Chest', 'Barbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie on a decline bench with your feet secured and your head lower than your hips.','Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.','Lower the barbell to your chest, keeping your elbows out to the sides.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'hl8DUh8'),
  ('db-0037', 'barbell decline wide-grip pullover', 'Back', 'Barbell', 'lats', ARRAY['triceps','chest']::text[], ARRAY['Lie on a decline bench with your head lower than your hips and your feet secured.','Hold a barbell with a wide grip and extend your arms straight above your chest.','Lower the barbell behind your head in a controlled manner, keeping your arms straight.','Pause for a moment, then raise the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Hj4FOCd'),
  ('db-0038', 'barbell drag curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.','Let the barbell hang at arm''s length in front of your thighs.','Keeping your upper arms stationary, curl the barbell up towards your chest by contracting your biceps.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'IENzBdA'),
  ('db-1370', 'barbell floor calf raise', 'Legs', 'Barbell', 'calves', ARRAY['hamstrings']::text[], ARRAY['Place a barbell on the floor in front of you.','Stand with the balls of your feet on the edge of the barbell, with your heels hanging off.','Hold onto a stable object for balance if needed.','Raise your heels as high as possible, using your calves to lift your body.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '2IHEa2T'),
  ('db-0039', 'barbell front chest squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Start by standing with your feet shoulder-width apart, toes slightly turned out.','Hold the barbell in front of your chest with your hands shoulder-width apart, elbows pointing forward.','Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.','Lower until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'IeTIEqg'),
  ('db-0041', 'barbell front raise', 'Shoulders', 'Barbell', 'delts', ARRAY['biceps','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.','Keep your arms straight and lift the barbell forward and upward until it reaches shoulder level.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'b2Uoz54'),
  ('db-0040', 'barbell front raise and pullover', 'Chest', 'Barbell', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.','Keep your arms straight and raise the barbell in front of you until it reaches shoulder height.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Next, lower the barbell behind your head, keeping your arms straight.','Pause for a moment at the bottom, then raise the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], '33AzZeV'),
  ('db-0042', 'barbell front squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Start by standing with your feet shoulder-width apart, toes slightly turned out.','Hold the barbell in front of your shoulders, resting it on your collarbone and shoulders.','Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.','Lower until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'zG0zs85'),
  ('db-0043', 'barbell full squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Stand with your feet shoulder-width apart, toes slightly turned out.','Hold the barbell across your upper back, resting it on your traps or rear delts.','Engage your core and keep your chest up as you begin to lower your body down.','Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.','Lower yourself until your thighs are parallel to the ground or slightly below.','Keep your knees in line with your toes and your weight in your heels.','Drive through your heels to stand back up, extending your hips and knees.','Repeat for the desired number of repetitions.']::text[], 'qXTaZnJ'),
  ('db-1461', 'barbell full squat (back pov)', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Stand with your feet shoulder-width apart, toes slightly turned out.','Hold the barbell across your upper back, resting it on your traps or rear delts.','Engage your core and keep your chest up as you begin to lower your body down.','Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.','Lower your body until your thighs are parallel to the ground or slightly below.','Keep your knees in line with your toes and your weight in your heels.','Drive through your heels to stand back up, extending your hips and knees.','Repeat for the desired number of repetitions.']::text[], 'DhMl549'),
  ('db-1462', 'barbell full squat (side pov)', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Stand with your feet shoulder-width apart, toes slightly turned out.','Hold the barbell across your upper back, resting it on your traps or rear delts.','Engage your core and keep your chest up as you begin to lower your body down.','Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.','Lower your body until your thighs are parallel to the ground or slightly below.','Keep your knees in line with your toes and your weight in your heels.','Drive through your heels to stand back up, extending your hips and knees.','Repeat for the desired number of repetitions.']::text[], 'iYzB0Cz'),
  ('db-1545', 'barbell full zercher squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Stand with your feet shoulder-width apart and toes slightly turned out.','Hold the barbell in the crooks of your elbows, with your hands gripping the barbell for stability.','Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.','Keep your knees in line with your toes and your weight in your heels.','Lower until your thighs are parallel to the ground, or as low as you can comfortably go.','Drive through your heels to stand back up, squeezing your glutes at the top of the movement.','Repeat for the desired number of repetitions.']::text[], 'vR1vold'),
  ('db-1409', 'barbell glute bridge', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Start by lying flat on your back on the ground with your knees bent and feet flat on the floor.','Place a barbell across your hips, holding it securely with both hands.','Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.','Pause for a moment at the top, squeezing your glutes.','Slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qKBpF7I'),
  ('db-3562', 'barbell glute bridge two legs on bench (male)', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','core']::text[], ARRAY['Start by sitting on the edge of a bench with your upper back resting against it and your feet flat on the ground, hip-width apart.','Place a barbell across your hips, holding it securely with both hands.','Engage your glutes and core muscles, then press through your heels to lift your hips off the bench, creating a straight line from your knees to your shoulders.','Pause for a moment at the top, squeezing your glutes.','Slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qg2PGl6'),
  ('db-0044', 'barbell good morning', 'Legs', 'Barbell', 'hamstrings', ARRAY['lower back']::text[], ARRAY['Start by standing with your feet shoulder-width apart and the barbell resting on your upper back.','Keeping your back straight and your core engaged, hinge forward at the hips, pushing your buttocks back as if you were trying to touch the wall behind you with your glutes.','Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.','Pause for a moment, then return to the starting position by squeezing your glutes and pushing your hips forward.','Repeat for the desired number of repetitions.']::text[], 'XlZ4lAC'),
  ('db-0045', 'barbell guillotine bench press', 'Chest', 'Barbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Lower the barbell slowly towards your neck, keeping your elbows pointed outwards.','Pause for a moment when the barbell is just above your neck.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'GXoaSgn'),
  ('db-0046', 'barbell hack squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start by standing with your feet shoulder-width apart and your toes slightly turned out.','Hold the barbell behind your legs, resting it on your upper thighs.','Lower your body by bending at the knees and hips, keeping your back straight and your chest up.','Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], '5VCj6iH'),
  ('db-1436', 'barbell high bar squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Stand with your feet shoulder-width apart, toes slightly turned out.','Place the barbell on your upper back, resting it on your traps.','Engage your core and keep your chest up as you begin to squat down, pushing your hips back and bending your knees.','Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go.','Drive through your heels to stand back up, extending your hips and knees.','Repeat for the desired number of repetitions.']::text[], 'Gnfo4FM'),
  ('db-0047', 'barbell incline bench press', 'Chest', 'Barbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Lie down on the bench with your feet flat on the ground.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle.','Pause for a moment at the bottom, then push the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], '3TZduzM'),
  ('db-1719', 'barbell incline close grip bench press', 'Arms', 'Barbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Lie down on the bench with your feet flat on the ground.','Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.','Pause for a moment when the barbell touches your chest.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'gx7s7uF'),
  ('db-0048', 'barbell incline reverse-grip press', 'Arms', 'Barbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Lie back on the bench and grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.','Unrack the barbell and lower it towards your upper chest, keeping your elbows tucked in.','Pause for a moment at the bottom, then push the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], '641mIfk'),
  ('db-0049', 'barbell incline row', 'Back', 'Barbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Lie face down on the bench with your chest against the pad and your feet flat on the ground.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Keep your back straight and your core engaged.','Pull the barbell towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'dmgMp3n'),
  ('db-0050', 'barbell incline shoulder raise', 'Chest', 'Barbell', 'serratus anterior', ARRAY['deltoids','trapezius']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Sit on the bench with your back against the pad and feet flat on the ground.','Hold a barbell with an overhand grip, slightly wider than shoulder-width apart.','Lift the barbell up to shoulder height, keeping your elbows slightly bent.','Slowly raise the barbell overhead, extending your arms fully.','Pause for a moment at the top, then slowly lower the barbell back to shoulder height.','Repeat for the desired number of repetitions.']::text[], 'xi0yckC'),
  ('db-0051', 'barbell jefferson squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and toes slightly turned out.','Hold the barbell with an overhand grip, resting it on the front of your body, just below your waist.','Step your left foot forward and your right foot back, keeping your feet shoulder-width apart.','Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.','Push through your heels to stand back up to the starting position.','Repeat the movement, alternating your forward and back foot with each repetition.']::text[], 'pkSoCW9'),
  ('db-0052', 'barbell jm bench press', 'Arms', 'Barbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Lower the barbell to your chest, keeping your elbows tucked in close to your body.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'ZsiqXYa'),
  ('db-0053', 'barbell jump squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.','Lower your body into a squat position by bending your knees and pushing your hips back.','Once you reach the bottom of the squat, explode upwards by jumping off the ground.','As you jump, extend your hips, knees, and ankles, pushing through your toes.','Land softly back into the squat position and immediately repeat the movement for the desired number of repetitions.']::text[], '1gFNTZV'),
  ('db-1410', 'barbell lateral lunge', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a barbell across your upper back.','Take a big step to the side with your right foot, keeping your left foot planted.','Bend your right knee and lower your body down into a lunge position, keeping your left leg straight.','Push off with your right foot and return to the starting position.','Repeat on the other side, stepping with your left foot.']::text[], 'py1HSzx'),
  ('db-1435', 'barbell low bar squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and the barbell resting on your upper back.','Keeping your chest up and core engaged, slowly lower your body by bending your knees and pushing your hips back.','Continue lowering until your thighs are parallel to the ground or slightly below.','Pause for a moment, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bTpEUcm'),
  ('db-0054', 'barbell lunge', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.','Take a step forward with your right foot, keeping your torso upright.','Lower your body by bending your right knee until your thigh is parallel to the ground.','Push through your right heel to return to the starting position.','Repeat with your left leg, alternating legs for the desired number of repetitions.']::text[], 't8iSghb'),
  ('db-1720', 'barbell lying back of the head tricep extension', 'Arms', 'Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.','Hold a barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.','Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows.','Pause for a moment, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'yg8Totb'),
  ('db-0055', 'barbell lying close-grip press', 'Arms', 'Barbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Grasp the barbell with a close grip, hands shoulder-width apart, palms facing towards your feet.','Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.','Slowly lower the barbell towards your chest, keeping your elbows close to your body.','Pause for a moment when the barbell touches your chest, then push it back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'EcaV7aL'),
  ('db-0056', 'barbell lying close-grip triceps extension', 'Arms', 'Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.','Grasp the barbell with a close grip, hands shoulder-width apart, palms facing up.','Extend your arms fully, lifting the barbell above your chest.','Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.','Pause for a moment at the bottom, then extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'HJ63mSO'),
  ('db-0057', 'barbell lying extension', 'Arms', 'Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.','Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.','Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.','Pause for a moment, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'EMpUwRI'),
  ('db-0058', 'barbell lying lifting (on hip)', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Lie flat on your back on a bench with your feet flat on the ground and your knees bent.','Hold the barbell with an overhand grip and position it on your hips.','Engaging your glutes, lift your hips off the bench until your body forms a straight line from your knees to your shoulders.','Pause for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'SNFfUff'),
  ('db-0059', 'barbell lying preacher curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a preacher bench with your chest against the pad and your arms extended over the edge, holding a barbell with an underhand grip.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'SYJ4Bkt'),
  ('db-0061', 'barbell lying triceps extension', 'Arms', 'Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.','Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.','Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.','Pause for a moment at the bottom, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'iZop9xO'),
  ('db-0060', 'barbell lying triceps extension skull crusher', 'Arms', 'Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.','Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.','Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.','Pause for a moment when the barbell is just above your forehead, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'h8LFzo9'),
  ('db-0063', 'barbell narrow stance squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and toes pointing slightly outward.','Hold the barbell across your upper back, resting it on your traps or rear delts.','Engage your core and keep your chest up as you slowly lower your body by bending your knees and pushing your hips back.','Continue lowering until your thighs are parallel to the ground or slightly below.','Pause for a moment, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'elhhVgj'),
  ('db-0064', 'barbell one arm bent over row', 'Back', 'Barbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with one hand using an overhand grip.','Bend forward at the hips, keeping your back straight and your head in a neutral position.','Pull the barbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.','Lower the barbell back down to the starting position in a controlled manner.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'Jsgsc27'),
  ('db-0065', 'barbell one arm floor press', 'Arms', 'Barbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie flat on your back on the floor with your knees bent and feet flat on the ground.','Hold the barbell with one hand, palm facing up, and extend your arm straight up over your chest.','Slowly lower the barbell towards your chest, keeping your elbow close to your body.','Pause for a moment at the bottom, then push the barbell back up to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'vtusOWT'),
  ('db-0066', 'barbell one arm side deadlift', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','quadriceps','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a barbell in one hand with an overhand grip.','Keep your back straight and your core engaged.','Bend at the hips and lower the barbell towards the outside of your leg, keeping your arm straight and your chest up.','Lower the barbell as far as you can while maintaining good form.','Pause for a moment, then slowly return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], '2DxtqHL'),
  ('db-0067', 'barbell one arm snatch', 'Shoulders', 'Barbell', 'delts', ARRAY['traps','forearms','core']::text[], ARRAY['Stand with your feet shoulder-width apart, toes pointing slightly outwards.','Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Bend your knees and lower your hips into a squat position, keeping your back straight and chest up.','Explosively extend your hips, knees, and ankles, driving the barbell upwards.','As the barbell reaches chest level, pull it upwards with your arm, keeping it close to your body.','Rotate your elbow under the barbell and extend your arm fully overhead, locking out your elbow.','Lower the barbell back down to the starting position in a controlled manner.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'xHKN2s8'),
  ('db-0068', 'barbell one leg squat', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell across your upper back.','Lift one foot off the ground and extend it forward, keeping it parallel to the ground.','Bend your standing leg and lower your body down as if sitting back into a chair, keeping your chest up and your back straight.','Lower yourself until your thigh is parallel to the ground, then push through your heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs and repeat.']::text[], 'uKyN64F'),
  ('db-0069', 'barbell overhead squat', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves','core']::text[], ARRAY['Stand with your feet shoulder-width apart and toes slightly turned out.','Hold the barbell with a wide grip, positioning it overhead with your arms fully extended.','Engage your core and lower your body down into a squat position, keeping your chest up and knees tracking over your toes.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'gfk9kD4'),
  ('db-1411', 'barbell palms down wrist curl over a bench', 'Arms', 'Barbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, palms facing down.','Hold a barbell with an overhand grip, hands shoulder-width apart.','Lower the barbell towards the ground by flexing your wrists, keeping your forearms stationary.','Pause for a moment at the bottom, then slowly raise the barbell back up by extending your wrists.','Repeat for the desired number of repetitions.']::text[], 'yzYH9pI'),
  ('db-1412', 'barbell palms up wrist curl over a bench', 'Arms', 'Barbell', 'forearms', ARRAY['biceps','shoulders']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up.','Rest your forearms on the bench, allowing your wrists to hang off the edge.','Keeping your forearms stationary, exhale and curl your wrists upwards as far as possible.','Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'SJAA2IQ'),
  ('db-3017', 'barbell pendlay row', 'Back', 'Barbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Bend forward at the hips, keeping your back straight and your chest up.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.','Lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'r0z6xzQ'),
  ('db-1751', 'barbell pin presses', 'Arms', 'Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Set up a barbell on a power rack at chest height.','Stand facing the barbell and position yourself underneath it, with your feet shoulder-width apart.','Grip the barbell with an overhand grip, slightly wider than shoulder-width apart.','Lift the barbell off the rack and hold it directly above your chest, with your arms fully extended.','Lower the barbell down towards your chest, keeping your elbows tucked in close to your body.','Pause for a moment when the barbell touches your chest.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'bndCa3Q'),
  ('db-0070', 'barbell preacher curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.','Grasp the barbell with an underhand grip, slightly wider than shoulder-width apart.','Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qOgPVf6'),
  ('db-0071', 'barbell press sit-up', 'Core', 'Barbell', 'abs', ARRAY['shoulders','chest']::text[], ARRAY['Lie flat on your back on a mat with your knees bent and feet flat on the ground.','Hold the barbell with an overhand grip, resting it on your chest.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'wnEscH8'),
  ('db-0072', 'barbell prone incline curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Lie face down on the bench with your chest and stomach resting against it.','Hold a barbell with an underhand grip, shoulder-width apart.','Extend your arms fully, allowing the barbell to hang down towards the floor.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'WLvTAv5'),
  ('db-0073', 'barbell pullover', 'Back', 'Barbell', 'lats', ARRAY['chest','triceps']::text[], ARRAY['Lie flat on a bench with your head at one end and your feet on the floor.','Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.','Keeping your arms straight, lower the barbell behind your head in a controlled manner until you feel a stretch in your lats.','Pause for a moment, then raise the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'i6LWjok'),
  ('db-0022', 'barbell pullover to press', 'Back', 'Barbell', 'lats', ARRAY['triceps','chest','shoulders']::text[], ARRAY['Lie flat on a bench with your head at one end and your feet on the ground.','Hold the barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.','Keeping your arms straight, lower the barbell behind your head in an arc-like motion until you feel a stretch in your lats.','Pause for a moment, then reverse the motion and press the barbell back to the starting position above your chest.','Repeat for the desired number of repetitions.']::text[], 'znLogoF'),
  ('db-0074', 'barbell rack pull', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Set up a barbell on a rack at knee height.','Stand with your feet shoulder-width apart, toes pointing slightly outwards.','Bend at the hips and knees to lower yourself down and grip the barbell with an overhand grip, hands shoulder-width apart.','Engage your core and lift the barbell by extending your hips and knees, pulling your shoulders back and squeezing your glutes at the top.','Lower the barbell back down to the starting position by bending at the hips and knees.','Repeat for the desired number of repetitions.']::text[], 'za9Ni4z'),
  ('db-0075', 'barbell rear delt raise', 'Shoulders', 'Barbell', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Raise the barbell out to the sides, keeping your arms straight, until they are parallel to the ground.','Pause for a moment at the top, then slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Ln9iTbU'),
  ('db-0076', 'barbell rear delt row', 'Shoulders', 'Barbell', 'delts', ARRAY['trapezius','rhomboids','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Bend forward at the hips, keeping your back straight and chest up.','Pull the barbell towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'S9zHIvU'),
  ('db-0078', 'barbell rear lunge', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.','Take a step backward with your right foot, landing on the ball of your foot.','Bend both knees to lower your body until your left thigh is parallel to the ground.','Push through your left heel to return to the starting position.','Repeat with the other leg.']::text[], 'VaP75jl'),
  ('db-0077', 'barbell rear lunge v. 2', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell across your upper back.','Take a step backward with your right foot, landing on the ball of your foot.','Bend both knees to lower your body until your left thigh is parallel to the ground.','Push through your left heel to return to the starting position.','Repeat with the other leg.']::text[], '62Nw60O'),
  ('db-0079', 'barbell revers wrist curl v. 2', 'Arms', 'Barbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench with your feet flat on the ground and your knees bent.','Hold a barbell with an overhand grip, palms facing down, and your hands shoulder-width apart.','Rest your forearms on your thighs, allowing your wrists to hang off the edge.','Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.','Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qDnGfDb'),
  ('db-2187', 'barbell reverse close-grip bench press', 'Arms', 'Barbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Grasp the barbell with a reverse grip, hands shoulder-width apart.','Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.','Slowly lower the barbell down towards your chest, keeping your elbows close to your body.','Pause for a moment when the barbell is just above your chest.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'YqJw82s'),
  ('db-0080', 'barbell reverse curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.','Keep your upper arms stationary and exhale as you curl the barbell upward, contracting your biceps.','Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale as you slowly lower the barbell back to the starting position, keeping your upper arms stationary.','Repeat for the desired number of repetitions.']::text[], 'xNrS20v'),
  ('db-0118', 'barbell reverse grip bent over row', 'Back', 'Barbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Hold a barbell with an overhand grip, palms facing down, and hands slightly wider than shoulder-width apart.','Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor.','Pull the barbell towards your lower chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'SzX3uzM'),
  ('db-1256', 'barbell reverse grip decline bench press', 'Chest', 'Barbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie on a decline bench with your feet secured and your head lower than your hips.','Grasp the barbell with a reverse grip, slightly wider than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.','Pause for a moment at the bottom, then push the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'DotAgEF'),
  ('db-1257', 'barbell reverse grip incline bench press', 'Chest', 'Barbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Lie down on the bench with your feet flat on the ground.','Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.','Pause for a moment when the barbell touches your chest.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'DU7I633'),
  ('db-1317', 'barbell reverse grip incline bench row', 'Back', 'Barbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Sit on the bench facing the backrest with your chest against it.','Grab the barbell with a reverse grip (palms facing down) and hands slightly wider than shoulder-width apart.','Keep your back straight and core engaged.','Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.','Pause for a moment at the top of the movement.','Slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], '8d8qJQI'),
  ('db-1721', 'barbell reverse grip skullcrusher', 'Arms', 'Barbell', 'triceps', ARRAY['forearms']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.','Hold the barbell with a reverse grip, palms facing towards your face, and your hands shoulder-width apart.','Extend your arms straight up over your chest, keeping your elbows in and your wrists straight.','Slowly lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.','Pause for a moment at the bottom, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'yRLPCLu'),
  ('db-0081', 'barbell reverse preacher curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a preacher bench with your chest against the pad and your arms extended straight down, holding a barbell with an overhand grip.','Keeping your upper arms stationary, exhale and curl the barbell upward while contracting your biceps.','Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], '4LIG9xr'),
  ('db-0082', 'barbell reverse wrist curl', 'Arms', 'Barbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down.','Rest your forearms on your thighs, allowing your wrists to hang off the edge.','Slowly curl your wrists upward, bringing the barbell towards your body.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'LsZkfU6'),
  ('db-0084', 'barbell rollerout', 'Core', 'Barbell', 'abs', ARRAY['lower back']::text[], ARRAY['Kneel on the floor and hold a barbell with both hands, shoulder-width apart.','Roll the barbell forward, extending your arms and keeping your core engaged.','Continue rolling forward until your body is fully extended and your arms are overhead.','Pause for a moment, then slowly roll the barbell back towards your knees, maintaining control.','Repeat for the desired number of repetitions.']::text[], '7M66AVi'),
  ('db-0083', 'barbell rollerout from bench', 'Core', 'Barbell', 'abs', ARRAY['shoulders','triceps']::text[], ARRAY['Start by kneeling on the floor with a barbell placed on a bench in front of you.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Keeping your core engaged and your back straight, slowly roll the barbell forward, extending your arms in front of you.','Continue rolling the barbell forward until your body is fully extended and your arms are overhead.','Pause for a moment at the fully extended position, then slowly roll the barbell back towards your body, returning to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Gxg9lDc'),
  ('db-0085', 'barbell romanian deadlift', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and your toes pointing forward.','Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Bend at the hips, keeping your back straight and your knees slightly bent.','Lower the barbell towards the ground, keeping it close to your body.','Feel the stretch in your hamstrings as you lower the barbell.','Once you feel a stretch in your hamstrings, push your hips forward and stand up straight.','Squeeze your glutes at the top of the movement.','Lower the barbell back down to the starting position and repeat for the desired number of repetitions.']::text[], 'wQ2c4XD'),
  ('db-0086', 'barbell seated behind head military press', 'Shoulders', 'Barbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.','Lift the barbell off the rack and bring it down to shoulder level, behind your head.','Press the barbell upward until your arms are fully extended.','Lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ngPpyRS'),
  ('db-0087', 'barbell seated bradford rocky press', 'Shoulders', 'Barbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.','Lift the barbell to shoulder height, keeping your elbows slightly bent and pointing forward.','Press the barbell overhead, fully extending your arms.','Lower the barbell back to shoulder height and repeat for the desired number of repetitions.']::text[], '0dCyly0'),
  ('db-0088', 'barbell seated calf raise', 'Legs', 'Barbell', 'calves', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Sit on a bench with your feet flat on the floor and a barbell resting on your thighs.','Place the balls of your feet on a raised platform, such as a block or step.','Position the barbell across your thighs and hold it securely with your hands.','Keeping your back straight and your core engaged, lift your heels off the ground by extending your ankles.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ktsFQAZ'),
  ('db-1371', 'barbell seated calf raise', 'Legs', 'Barbell', 'calves', ARRAY['hamstrings']::text[], ARRAY['Sit on a bench with your feet flat on the floor and a barbell resting on your thighs.','Place the balls of your feet on a raised platform, such as a block or step.','Lower your heels as far as possible, feeling a stretch in your calves.','Raise your heels as high as possible, contracting your calves.','Repeat for the desired number of repetitions.']::text[], 'ipvgBnC'),
  ('db-1718', 'barbell seated close grip behind neck triceps extension', 'Arms', 'Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold the barbell with a close grip behind your neck, palms facing forward.','Keep your elbows close to your head and slowly lower the barbell towards the back of your head.','Pause for a moment, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], '4CBIBOM'),
  ('db-0089', 'barbell seated close-grip concentration curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your feet flat on the floor and hold a barbell with an underhand grip, hands shoulder-width apart.','Rest your upper arms against your inner thighs, just above your knees, and let the barbell hang down in front of you.','Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders, contracting your biceps.','Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '1V1gj1u'),
  ('db-0090', 'barbell seated good morning', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Sit on a bench with your feet flat on the ground and a barbell resting on your upper back.','Keep your back straight and your chest up.','Slowly hinge forward at the hips, lowering your torso towards the ground.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'd960PgE'),
  ('db-0091', 'barbell seated overhead press', 'Shoulders', 'Barbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.','Lift the barbell off the rack and bring it to shoulder level, with your elbows bent and palms facing forward.','Press the barbell overhead by extending your arms fully.','Pause for a moment at the top, then slowly lower the barbell back to shoulder level.','Repeat for the desired number of repetitions.']::text[], 'kTbSH9h'),
  ('db-0092', 'barbell seated overhead triceps extension', 'Arms', 'Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead.','Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head.','Pause for a moment, then extend your arms to raise the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], '5uFK1xr'),
  ('db-0094', 'barbell seated twist', 'Core', 'Barbell', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Sit on a flat bench with your feet flat on the ground and your knees bent.','Hold a barbell with both hands in front of your chest, keeping your elbows slightly bent.','Engage your core and slowly twist your torso to one side, keeping your back straight.','Pause for a moment at the end of the twist, then slowly rotate back to the starting position.','Repeat the twist to the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'dFSNDOA'),
  ('db-0095', 'barbell shrug', 'Back', 'Barbell', 'traps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell in front of you with an overhand grip.','Keep your arms straight and your back straight throughout the exercise.','Lift your shoulders up towards your ears as high as possible, squeezing your traps at the top.','Hold for a moment, then slowly lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'dG7tG5y'),
  ('db-0096', 'barbell side bent v. 2', 'Core', 'Barbell', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with both hands, palms facing down.','Keep your back straight and core engaged throughout the exercise.','Slowly bend your torso to the right side, lowering the barbell towards your right knee.','Pause for a moment, then return to the starting position.','Repeat the movement on the left side.','Continue alternating sides for the desired number of repetitions.']::text[], 'i4JkUaL'),
  ('db-0098', 'barbell side split squat', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.','Hold a barbell across your upper back, resting it on your traps.','Engage your core and keep your chest up as you lower your body down into a squat position, bending at the knees and hips.','As you lower, push your knees out to the sides and keep your weight on your heels.','Lower until your thighs are parallel to the ground, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'W31mMjd'),
  ('db-0097', 'barbell side split squat v. 2', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand with your feet wider than shoulder-width apart, toes pointing slightly outwards.','Hold a barbell across your upper back, resting it on your shoulders.','Take a big step to the side with your right foot, keeping your left foot planted.','Bend your right knee and lower your body down into a squat position, keeping your chest up and your back straight.','Push through your right heel to return to the starting position.','Repeat on the other side, stepping out with your left foot.','Continue alternating sides for the desired number of repetitions.']::text[], 'HUEqZ1y'),
  ('db-1756', 'barbell single leg deadlift', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand with your feet hip-width apart, holding a barbell in front of your thighs with an overhand grip.','Shift your weight onto your left foot and lift your right foot slightly off the ground.','Hinge forward at the hips, keeping your back straight and your right leg extended behind you for balance.','Lower the barbell towards the ground, keeping it close to your body and your left leg slightly bent.','Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'gEyURal'),
  ('db-0099', 'barbell single leg split squat', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a barbell across your upper back.','Take a large step forward with one leg, keeping your torso upright.','Lower your body by bending your front knee and hip, while keeping your back leg straight.','Continue lowering until your front thigh is parallel to the ground.','Pause for a moment, then push through your front heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'gGNQmVt'),
  ('db-2799', 'barbell sitted alternate leg raise', 'Core', 'Barbell', 'abs', ARRAY['hip flexors']::text[], ARRAY['Sit on a bench with your back straight and hold a barbell across your thighs.','Keeping your legs straight, lift one leg up as high as possible while keeping the other leg on the ground.','Lower the raised leg back down and repeat with the other leg.','Continue alternating legs for the desired number of repetitions.']::text[], 'G7xoEzr')
